class Solution:
    def closestOccurrence(self, nums, queries):
        # Create a dictionary to map each value to the list of indices where it appears
        val_to_indices = {}
        for idx, num in enumerate(nums):
            if num not in val_to_indices:
                val_to_indices[num] = []
            val_to_indices[num].append(idx)

        result = []
        for i, k in queries:
            target = nums[i]
            indices = val_to_indices.get(target, [])
            # If there's only one occurrence, or none (but it should at least have the current one)
            if len(indices) <= 1:
                result.append(-1)
                continue

            # The list of indices is sorted, so we can perform binary search
            pos = bisect_left(indices, k)
            candidates = []
            # Check left neighbor
            if pos > 0:
                candidates.append(indices[pos - 1])
            # Check right neighbor
            if pos < len(indices):
                # If the current position is the same as k, we need to skip if it's the original index
                if indices[pos] != k or (indices[pos] == k and i != k):
                    candidates.append(indices[pos])
            # If i is k and the exact match is i itself, we need to ignore it in the candidates
            if len(candidates) == 0:
                result.append(-1)
            else:
                # Find the closest
                closest_idx = None
                min_dist = float('inf')
                for candidate in candidates:
                    if candidate == i and k == i:
                        continue  # skip the query's own index if it's the same as k and it's the only occurrence
                    dist = abs(candidate - k)
                    if dist < min_dist or (dist == min_dist and candidate < closest_idx):
                        min_dist = dist
                        closest_idx = candidate
                if closest_idx is None:
                    result.append(-1)
                else:
                    result.append(closest_idx)
        return result

