    # Create a dictionary to map each value to the list of indices where it occurs
    value_indices = {}
    for idx, num in enumerate(arr):
        if num not in value_indices:
            value_indices[num] = []
        value_indices[num].append(idx)

    result = []
    for query in queries:
        i, k = query
        if i >= len(arr):
            result.append(-1)
            continue
        target = arr[i]
        # Check if the target exists in the array and if so, has indices
        if target not in value_indices:
            result.append(-1)
            continue
        indices = value_indices[target]
        # Use bisect to find the first occurrence >= k
        pos = bisect.bisect_left(indices, k)
        if pos < len(indices) and indices[pos] == k:
            result.append(k)
        else:
            if pos < len(indices):
                result.append(indices[pos])
            else:
                result.append(-1)
    return result

