def find_rightmost_occurrence(nums, queries):
    # Create a dictionary to map each value to the list of indices where it occurs
    value_indices = {}
    for idx, num in enumerate(nums):
        if num not in value_indices:
            value_indices[num] = []
        value_indices[num].append(idx)

    result = []
    for query in queries:
        i, k = query
        if i >= len(nums):
            result.append(-1)
            continue
        target = nums[i]
        if target not in value_indices:
            result.append(-1)
            continue
        indices = value_indices[target]
        # Perform binary search to find the rightmost occurrence <= k
        left, right = 0, len(indices) - 1
        answer = -1
        while left <= right:
            mid = (left + right) // 2
            if indices[mid] <= k:
                answer = indices[mid]
                left = mid + 1
            else:
                right = mid - 1
        result.append(answer)
    return result
